import{_ as a,o as t,c as r,ak as s}from"./chunks/framework.aEAtsvX-.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"大熊猫服务器文档v2","text":"教程、指南与规则","tagline":"服务器版本1.21.11 / 腐竹是萝莉控大蟑螂","actions":[{"theme":"brand","text":"⚡️【新手必看】安装和开始","link":"/install_and_start"},{"theme":"alt","text":"注意事项","link":"/notice"},{"theme":"alt","text":"插件与命令教程","link":"/plugins/"},{"theme":"alt","text":"进阶","link":"/advance/"},{"theme":"brand","text":"赞助服务器","link":"/index#赞助服务器"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1776343201000}'),i={name:"index.md"};function l(o,e,n,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<div class="tip custom-block"><p class="custom-block-title">🐧QQ群号276051457</p><p>愣着干嘛快进群</p></div><h2 id="欢迎" tabindex="-1">欢迎！ <a class="header-anchor" href="#欢迎" aria-label="Permalink to “欢迎！”">​</a></h2><p>我们是大熊猫服务器，一个<mark>高版本生存服</mark>！</p><p>我们追求原版体验，但是又引入了插件以提升娱乐性。</p><p>服务器适合养老，玩家氛围和谐，群友们很喜欢聊日常。</p><h2 id="关于大熊猫服务器" tabindex="-1">关于大熊猫服务器 <a class="header-anchor" href="#关于大熊猫服务器" aria-label="Permalink to “关于大熊猫服务器”">​</a></h2><p>这是一个始于2019年9月的老牌服务器。自Minecraft 1.14版本开服，历经数个版本周期与周目，始终由服主一人独立管理、更新与维护，坚持运营至今。</p><h3 id="对于转型的考量" tabindex="-1">对于转型的考量 <a class="header-anchor" href="#对于转型的考量" aria-label="Permalink to “对于转型的考量”">​</a></h3><p>由于服务器运营需要承担电费、网费等基础开销，无法长期维持公益模式，自1.14版本后已全面转为商业服务器。我们坚持使用正版插件以确保稳定与安全，并注重售后维护。<strong>虽然转为商业运营，但游戏内充值玩家与非充值玩家之间的差距很小，不会因赞助而偏袒任何玩家，全力保障所有玩家的公平游戏体验。</strong></p><h3 id="对于未来" tabindex="-1">对于未来 <a class="header-anchor" href="#对于未来" aria-label="Permalink to “对于未来”">​</a></h3><p><strong>本服正朝轻RPG与多元化玩法发展，定位为插件服，而非纯粹的生电服。</strong> 在不完全禁止生电行为的前提下会进行适当限制，属于半生电服。通过拓展更多游戏内容，旨在延长服务器生命周期，为玩家提供持久而丰富的体验。</p><h2 id="赞助服务器" tabindex="-1">赞助服务器 <a class="header-anchor" href="#赞助服务器" aria-label="Permalink to “赞助服务器”">​</a></h2><p><strong>赞助是获得不影响游戏平衡的游戏权限的重要途径</strong>，主要包括三种方式：直接购买点券、购买月卡（减负包）以及参与众筹。</p><details class="details custom-block"><summary>点券</summary><p>点券是用于购买权限的主要代币，<strong>可兑换游戏币、装饰性或功能性的权限（如彩色聊天字体、更多附魔查询、称号装饰、增加上架物品数量等）</strong>，有效期通常为一个月。</p></details><details class="details custom-block"><summary>月卡</summary><p>月卡（减负包）为按月订阅服务，购买后可一次性获得200点券，并每日领取800游戏币和一个不死图腾；在有效期内，还能享受圈地价格降低0.1、领地上限+1，以及mcmmo经验获取增加10%的福利。</p></details><details class="details custom-block"><summary>众筹</summary><p>众筹则在服务器需要添加新插件时开放，<strong>由多名玩家共同赞助以筹集所需金额</strong>。参与众筹的玩家将加入众筹组，获得额外的领地及设家上限，并解锁部分娱乐和功能性插件权限（例如CMI的装饰性功能，如<code>/ride</code>、<code>/hat</code>、盔甲架编辑等），<strong>这些权限均以娱乐和便利为主，不会影响玩家间的游戏平衡。</strong></p></details><p>前两种可以在游戏中输入<code>/菜单</code>后，于界面右下角点击赞助菜单进入相关界面。</p><hr><p><a href="https://github.com/Redersha/panda_server_guide_v2" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/github-repo-blue?logo=github" alt="GitHub Repo"></a> <a href="https://github.com/Redersha/panda_server_guide_v2?tab=MIT-1-ov-file" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/License-MIT-lightgrey.svg" alt="License: MIT"></a> <a href="https://vitepress.dev/zh/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/PoweredBy-VitePress-purple" alt="Powered%20By: VitePress"></a></p>',19)])])}const g=a(i,[["render",l]]);export{m as __pageData,g as default};
